const items = [];
const seen = new Set();

// ── DATE FILTER: skip news older than 7 days ──
const cutoffDate = new Date();
cutoffDate.setDate(cutoffDate.getDate() - 7);

for (const item of $input.all()) {
  const raw = item.json.data || '';

  // ── RSS/XML handling ──
  if (raw.includes('<item>')) {
    const matches = [...raw.matchAll(/<item>([\s\S]*?)<\/item>/g)];

    for (const match of matches) {
      const block = match[1];

      const get = (tag) => {
        const m = block.match(
          new RegExp(`<${tag}[^>]*><!\\[CDATA\\[([\\s\\S]*?)\\]\\]><\\/${tag}>|<${tag}[^>]*>([\\s\\S]*?)<\\/${tag}>`)
        );
        return m ? (m[1] || m[2] || '').trim() : '';
      };

      const guid = get('guid') || get('link');
      if (!guid || seen.has(guid)) continue;

      // ── 7-day date filter for news ──
      const pubDateStr = get('pubDate');
      if (pubDateStr) {
        const pubDate = new Date(pubDateStr);
        if (!isNaN(pubDate.getTime()) && pubDate < cutoffDate) continue;
      }

      seen.add(guid);
      items.push({ json: {
        data_type: 'news',
        title: get('title').replace(/<!\[CDATA\[|\]\]>/g, '').trim(),
        description: get('description').replace(/<[^>]*>/g, '').substring(0, 300),
        link: get('link'),
        pubDate: pubDateStr,
        guid,
        source: raw.includes('economictimes') ? 'ET Markets' : 'Google News'
      }});
    }
  }

  // ── CSV handling (Insider trades + Bulk deals) ──
  else if (raw.includes(',') && raw.includes('\n')) {
    const lines = raw.trim().split('\n').filter(l => l.trim());
    if (lines.length < 2) continue;

    const headers = lines[0]
      .replace(/"/g, '')
      .split(',')
      .map(h => h.trim().toLowerCase().replace(/[\s\/\(\)]+/g, '_'));

    for (let i = 1; i < Math.min(lines.length, 100); i++) {
      const values = lines[i].replace(/"/g, '').split(',');
      const obj = {};
      headers.forEach((h, idx) => {
        obj[h] = (values[idx] || '').trim();
      });

      const symbol = obj.symbol || obj.scrip_code || '';
      const date = obj.date || obj.trade_date || obj.acquisition_date || '';
      const guid = `csv-${symbol}-${date}-${i}`;

      if (!symbol || seen.has(guid)) continue;

      // ── 7-day date filter for CSV items ──
      if (date) {
        const itemDate = new Date(date);
        if (!isNaN(itemDate.getTime()) && itemDate < cutoffDate) continue;
      }

      seen.add(guid);

      const isInsider = headers.some(function(h) {
        return h.includes('acquirer') ||
          h.includes('disposer') ||
          h.includes('category_of_person');
      });

      const isIndexList = headers.some(function(h) {
        return h.includes('company_name') || h.includes('isin_code');
      }) && !headers.some(function(h) {
        return h.includes('quantity') ||
          h.includes('price') ||
          h.includes('value') ||
          h.includes('buy') ||
          h.includes('sell');
      });

      if (isIndexList) continue;

      items.push({ json: {
        data_type: isInsider ? 'insider_trade' : 'bulk_deal',
        symbol: symbol.toUpperCase(),
        ...obj,
        guid,
        source: 'NSE'
      }});
    }
  }
}

return items.length > 0 ? items : [];

// ── READ PORTFOLIO FROM SUPABASE (by node name, no wiring needed) ──
