}

// ── READ NIFTY 500 (by node name) ──
var NIFTY500 = [];
try {
  var niftyItems = $('Fetch Nifty 500 List').all();
  for (var i = 0; i < niftyItems.length; i++) {
    var raw = niftyItems[i].json.data || '';
    if (raw.includes('Company Name') && raw.includes('Symbol')) {
      var lines = raw.trim().split('\n');
      for (var j = 1; j < lines.length; j++) {
        var cols = lines[j].split(',');
        var sym = (cols[2] || '').replace(/"/g, '').trim().toUpperCase();
        if (sym && sym.length > 1) NIFTY500.push(sym);
      }
      break;
    }
  }
} catch(e) {}

// Nifty 500 fallback
if (NIFTY500.length === 0) {
  NIFTY500 = [
    'WIPRO','SUNPHARMA','BAJFINANCE','ICICIBANK','KOTAKBANK','AXISBANK',
    'HINDUNILVR','ASIANPAINT','MARUTI','NESTLEIND','TITAN','ULTRACEMCO',
    'TECHM','POWERGRID','NTPC','ONGC','COALINDIA','BPCL','HEROMOTOCO',
    'DIVISLAB','CIPLA','DRREDDY','APOLLOHOSP','ADANIENT','ADANIPORTS',
    'TATASTEEL','JSWSTEEL','HINDALCO','SAIL','BAJAJFINSV','BAJAJ-AUTO',
    'EICHERMOT','TATACONSUM','DABUR','MARICO','GODREJCP','PIDILITIND',
    'BERGEPAINT','HAVELLS','VOLTAS','INDIGO','IRCTC','CONCOR','BANDHANBNK',
    'FEDERALBNK','IDFCFIRSTB','PNB','CANBK','UNIONBANK','BANKBARODA',
    'INDUSINDBK','VEDL','ITC','BRITANNIA','COLPAL','LICI','SBILIFE',
    'HDFCLIFE','DMART','NYKAA','PAYTM','ZYDUSLIFE','TRENT','PERSISTENT',
    'LTIM','MUTHOOTFIN','GAIL','IOC','TATACHEM','COFORGE','OFSS'
  ];
}

// ── MAIN MATCHING LOOP ──
var PORTFOLIO = Object.keys(PORTFOLIO_MAP);
var results = [];

for (var k = 0; k < $input.all().length; k++) {
  var item = $input.all()[k];
  var data = item.json;

  // Skip Nifty 500 CSV rows
  var rawCheck = data.data || '';
  if (rawCheck.includes('Company Name') && rawCheck.includes('Symbol')) continue;

  // Skip items with no content
  if (!data.title && !data.symbol) continue;

  // Skip empty bulk deals
  if (data.data_type === 'bulk_deal' && !data.date && !data.quantity_traded) continue;

  var searchText = ' ' + JSON.stringify(data).toUpperCase() + ' ';
  var csvTicker = (data.symbol || '').toUpperCase();

  // Check portfolio match
  var inPortfolio = false;
  var matchedTicker = '';

  for (var p = 0; p < PORTFOLIO.length; p++) {
    var ticker = PORTFOLIO[p];
    var names = PORTFOLIO_MAP[ticker];
    var matched = (csvTicker === ticker);

    if (!matched) {
      for (var n = 0; n < names.length; n++) {
        var name = names[n].toUpperCase();
        if (searchText.includes(' ' + name + ' ') ||
            searchText.includes('"' + name + '"') ||
            searchText.includes(' ' + name + ',') ||
            searchText.includes(' ' + name + '.')) {
          matched = true; break;
        }
      }
    }
    if (matched) { inPortfolio = true; matchedTicker = ticker; break; }
  }

  // Check Nifty 500 match (only if not portfolio)
  var inUniverse = false;
  if (!inPortfolio) {
    for (var u = 0; u < NIFTY500.length; u++) {
      var ut = NIFTY500[u];
      if (csvTicker === ut ||
          searchText.includes(' ' + ut + ' ') ||
          searchText.includes('"' + ut + '"')) {
        inUniverse = true; break;
      }
    }
  }

  // Tag and output
  if (inPortfolio) {
    results.push({ json: {
      ...data,
      matched_ticker: matchedTicker,
      monitoring_type: 'portfolio',
      tier_threshold: 'all'
    }});
  } else if (inUniverse) {
    results.push({ json: {
      ...data,
      monitoring_type: 'universe',
      tier_threshold: 'medium_and_above'
    }});
  }
}

return results.length > 0 ? results : [];

const item = $('Keyword Filter').first().json;

const title = (item.title || item.symbol || 'Unknown event')
  .replace(/<!\[CDATA\[|\]\]>/g, '')
  .trim();

const company = item.matched_ticker || item.symbol || 'Unknown';
const source = item.source || 'Unknown';
const guid = item.guid || item.link || '';

const details = (item.description || item.full_context || '')
  .replace(/<!\[CDATA\[|\]\]>/g, '')
  .substring(0, 200);

const prompt = `Research this Indian market event:
Event: ${title}
Company: ${company}
Source: ${source}
Details: ${details}

Provide: full context with exact numbers, historical precedent for this company, sector peer comparison. Under 300 words.`;

const payload = {
  model: 'sonar',
  max_tokens: 500,
  messages: [
    {
      role: 'system',
      content: 'You are a financial research assistant for Indian stock markets. Be specific and concise.'
    },
    {
      role: 'user',
      content: prompt
    }
  ]
};

return [{
  json: {
    perplexity_payload: JSON.stringify(payload),
    guid: guid,
    title: item.title,
    matched_ticker: item.matched_ticker,
    monitoring_type: item.monitoring_type,
    tier_threshold: item.tier_threshold,
    source: item.source,
    link: item.link,
    pubDate: item.pubDate,
    symbol: item.symbol,
    data_type: item.data_type,
    description: item.description
  }
}];

const perplexityResponse = $input.first().json;

// Read original signal data from Keyword Filter
const originalItem = $('Keyword Filter').first().json;

const perplexityContent = perplexityResponse.choices?.[0]?.message?.content
  || perplexityResponse.perplexity_context
  || '';

const citations = (perplexityResponse.citations || [])
  .slice(0, 3)
  .join(', ');

const cleanTitle = (originalItem.title || originalItem.symbol || '')
  .replace(/<!\[CDATA\[|\]\]>/g, '')
  .trim();

return [{
  json: {
    // Original signal fields
    guid: originalItem.guid || originalItem.link || '',
    title: cleanTitle,
    matched_ticker: originalItem.matched_ticker,
    monitoring_type: originalItem.monitoring_type,
    tier_threshold: originalItem.tier_threshold,
    source: originalItem.source,
    original_link: originalItem.original_link || originalItem.link || '',
    pubDate: originalItem.pubDate,
    symbol: originalItem.symbol,
    data_type: originalItem.data_type,
    description: originalItem.description,

    // Perplexity enrichment
    perplexity_context: perplexityContent,
    perplexity_citations: citations,
  }
}];

const response = $input.first().json;
const originalItem = $('Build AI Payload').first().json;

// Extract text from OpenAI response
const rawText = response.choices?.[0]?.message?.content || '';

// Parse JSON
let signal = {};
try {
  const cleaned = rawText
    .replace(/```json/g, '')
    .replace(/```/g, '')
    .trim();
  signal = JSON.parse(cleaned);
} catch(e) {
  signal = {
    signal_tier: "noise",
    ticker: originalItem.symbol || originalItem.matched_ticker || 'UNKNOWN',
    event_type: originalItem.data_type || 'news',
    headline: "Parse error — signal could not be extracted",
    what_happened: rawText.substring(0, 200),
    why_it_matters: "JSON parsing failed",
    historical_precedent: "No comparable prior event found",
    sector_context: "Unknown",
    watch_for_next: "Manual review required",
    source: originalItem.source || 'Unknown',
    confidence: "low",
    confidence_reason: "JSON parsing failed: " + e.message
  };
}

// ── QUALITY GATES ──
const warnings = [];

// Gate 1: Downgrade HIGH→MEDIUM if no historical precedent
if (signal.signal_tier === 'high' &&
    (!signal.historical_precedent ||
     signal.historical_precedent === 'No comparable prior event found')) {
  signal.signal_tier = 'medium';
  signal.confidence = signal.confidence === 'high' ? 'medium' : signal.confidence;
  warnings.push('Downgraded HIGH→MEDIUM: no historical precedent provided');
}

// Gate 2: Downgrade HIGH→MEDIUM for pure news items without hard evidence
if (signal.signal_tier === 'high' && signal.event_type === 'news') {
  signal.signal_tier = 'medium';
  warnings.push('Downgraded HIGH→MEDIUM: news items require filing/insider confirmation for HIGH tier');
}

// Gate 3: Force low confidence if multiple named individuals detected
// (risk of cross-contamination between people)
const nameMatches = (signal.what_happened || '').match(/[A-Z][a-z]+ [A-Z][a-z]+/g) || [];
if (nameMatches.length >= 3 && signal.confidence === 'high') {
  signal.confidence = 'medium';
  warnings.push('Confidence capped at medium: multiple named individuals detected');
}

// Gate 4: Flag suspiciously large rupee figures for manual review
const text = JSON.stringify(signal);
const largeFigures = text.match(/₹[\d,]+\s*[Cc]r|Rs\.?\s*[\d,]+\s*[Cc]r/g) || [];
largeFigures.forEach(fig => {
  const num = parseInt(fig.replace(/[^\d]/g, ''));
  if (num > 50000) {
    warnings.push(`Large figure detected (${fig}) — verify against source`);
    if (signal.confidence === 'high') signal.confidence = 'medium';
  }
});

return [{
  json: {
    ...signal,
    monitoring_type: originalItem.monitoring_type || 'universe',
    original_link: originalItem.original_link || originalItem.link || '',
    original_source: originalItem.original_source || originalItem.source || '',
    original_pub_date: originalItem.pubDate || '',
    perplexity_citations: originalItem.perplexity_citations || '',
    processed_at: new Date().toISOString(),
    guid: originalItem.guid || originalItem.link || '',
    quality_warnings: warnings.length > 0 ? warnings.join(' | ') : null
  }
}];

var HIGH_SIGNAL_KEYWORDS = [
  'INSIDER', 'BULK DEAL', 'BLOCK DEAL', 'PROMOTER',
  'CFO', 'CEO', 'MD ', 'CTO ', 'RESIGN', 'STEP DOWN',
  'ACQUI', 'MERGER', 'TAKEOVER', 'OPEN OFFER',
  'FRAUD', 'SEBI', 'PENALTY', 'INVESTIGATION', 'WHISTLEBLOWER',
  'BUYBACK', 'DELISTING', 'QIP', 'FPO',
  'DEFAULT', 'NPA', 'RESTRUCTUR'
];

var MEDIUM_SIGNAL_KEYWORDS = [
  'GUIDANCE', 'DOWNGRADE', 'UPGRADE', 'OUTLOOK',
  'STAKE', 'STAKE SALE', 'STAKE BUY',
  'BEAT ESTIMATE', 'MISS ESTIMATE', 'PROFIT JUMP', 'LOSS WIDEN',
  'MARGIN EXPAND', 'MARGIN CONTRACT', 'REVENUE SURGE', 'REVENUE DECLINE',
  'ANALYST', 'TARGET PRICE', 'RATING', 'OVERWEIGHT', 'UNDERWEIGHT',
  'BLOCK DEAL', 'PORTFOLIO', 'FUND HOUSE', 'FII', 'DII',
  'QUARTERLY RESULT', 'Q1', 'Q2', 'Q3', 'Q4', 'EARNINGS',
  'PARTNERSHIP', 'JOINT VENTURE', 'CONTRACT WIN', 'ORDER WIN',
  'EXPANSION', 'CAPEX', 'FUNDRAISE', 'RIGHTS ISSUE'
];

var results = [];

for (var i = 0; i < $input.all().length; i++) {
  var item = $input.all()[i];
  var data = item.json;

  // Skip items with no content
  if (!data.title && !data.symbol && !data.headline) continue;

  // Ensure every item has a guid
  if (!data.guid) {
    data.guid = (data.link || data.title || data.symbol || Math.random().toString()).substring(0, 100);
  }

  // Portfolio items — always pass through
  if (data.monitoring_type === 'portfolio') {
    results.push({ json: data });
    continue;
  }

  // Universe items — pass if high OR medium signal keyword found
  if (data.monitoring_type === 'universe') {
    var text = JSON.stringify(data).toUpperCase();

    var isHighSignal = false;
    for (var k = 0; k < HIGH_SIGNAL_KEYWORDS.length; k++) {
      if (text.includes(HIGH_SIGNAL_KEYWORDS[k])) {
        isHighSignal = true; break;
      }
    }

    var isMediumSignal = false;
    if (!isHighSignal) {
      for (var m = 0; m < MEDIUM_SIGNAL_KEYWORDS.length; m++) {
        if (text.includes(MEDIUM_SIGNAL_KEYWORDS[m])) {
          isMediumSignal = true; break;
        }
      }
    }

    if (isHighSignal || isMediumSignal) {
      results.push({ json: data });
    }
  }
}

return results;

const fetchResult = $input.first().json;
const previousItem = $('Extract Perplexity Response').first().json;

// Get raw HTML from the fetch result
let rawHtml = '';
try {
  rawHtml = fetchResult.data || fetchResult.body || fetchResult.content || '';
  // If data is an object, stringify it
  if (typeof rawHtml === 'object') rawHtml = JSON.stringify(rawHtml);
} catch(e) {
  rawHtml = '';
}

// Strip HTML tags and clean text
let articleText = rawHtml
  .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
  .replace(/<header[^>]*>[\s\S]*?<\/header>/gi, '')
  .replace(/<footer[^>]*>[\s\S]*?<\/footer>/gi, '')
  .replace(/<nav[^>]*>[\s\S]*?<\/nav>/gi, '')
  .replace(/<aside[^>]*>[\s\S]*?<\/aside>/gi, '')
  .replace(/<form[^>]*>[\s\S]*?<\/form>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"')
  .replace(/&#39;/g, "'")
  .replace(/&nbsp;/g, ' ')
  .replace(/\s+/g, ' ')
  .trim()
  .substring(0, 4000);

// Strict paywall detection — only exact phrases
const paywallPhrases = [
  'sign in to read full article',
  'subscribe to continue reading',
  'login to continue reading',
  'create a free account to read',
  'this article is for subscribers',
  'subscribe now to read'
];
const isPaywalled = paywallPhrases.some(p =>
  articleText.toLowerCase().includes(p)
);

// Only fall back if truly paywalled or article is too short to be useful
const isUsable = !isPaywalled && articleText.length > 150;

const finalContext = isUsable
  ? articleText
  : (previousItem.perplexity_context || 'No context available');

return [{
  json: {
    ...previousItem,
    article_text: finalContext,
    fetch_success: isUsable,
    fetch_note: isUsable
      ? `Raw article fetched — ${articleText.length} chars`
      : `Fallback to Perplexity — ${isPaywalled ? 'paywalled' : 'article too short'}`
  }
}];
